package pl.msurvival.welcome;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.player.*;import org.bukkit.plugin.java.JavaPlugin;import java.util.*;public final class MSurvivalWelcome extends JavaPlugin implements Listener{public void onEnable(){saveDefaultConfig();Bukkit.getPluginManager().registerEvents(this,this);}public boolean onCommand(CommandSender s,Command c,String l,String[] a){String n=c.getName().toLowerCase();send(s,getConfig().getStringList(n.equals("donate")?"donate":"help"));return true;}@EventHandler public void join(PlayerJoinEvent e){Player p=e.getPlayer();if(getConfig().getBoolean("title.enabled",true))p.sendTitle(color(getConfig().getString("title.title")),color(getConfig().getString("title.subtitle")),10,60,10);send(p,getConfig().getStringList("welcome"));}private void send(CommandSender s,List<String> lines){for(String x:lines)s.sendMessage(color(x.replace("%player%",s.getName())));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}